const crypto = require('crypto');
const source = $input.first().json.body || {};
const meta = source._n8n || {};
const callback = {
  eventLogId: meta.eventLogId,
  requestId: source.requestId || `approval-rejected-${Date.now()}`,
  idempotencyKey: meta.idempotencyKey || '',
  workflowCode: 'approval-rejected',
  eventType: 'approval.rejected',
  workflowStatus: 'COMPLETED',
  workflowName: meta.workflowName || 'approval-rejected',
  workflowVersion: meta.workflowVersion || '2026.04.1',
  workflowDomain: meta.workflowDomain || 'approval',
  workflowOwner: meta.workflowOwner || 'platform-ops',
  externalExecutionId: `n8n-${$execution.id}`,
  errorCode: null,
  errorMessage: null,
  errorSummary: null,
  processingTimeMs: 0,
  manualStatus: null,
  manualReason: null
};
const rawBody = JSON.stringify(callback);
const timestamp = String(Math.floor(Date.now() / 1000));
const signature = crypto
  .createHmac('sha256', $env.N8N_WEBHOOK_SECRET)
  .update([callback.requestId, callback.eventType, callback.workflowCode, timestamp, rawBody].join('\n'))
  .digest('hex');
return [{ json: { callback, timestamp, signature } }];
